const constants = {
  VOICE_LIST_URL: "https://speech.platform.bing.com/consumer/speech/synthesize/readaloud/voices/list?trustedclienttoken=6A5AA1D4EAFF4E9FB37E23D68491D6F4",
  VOICE_HEADERS: {
    "Content-Type": "application/json",
    "Accept": "application/json",
  },
  OUTPUT_FORMATS: {
    AUDIO_24KHZ_48KBITRATE_MONO_MP3: { tag: "audio-24khz-48kbitrate-mono-mp3", ext: ".mp3", mimeType: "audio/mpeg" },
    AUDIO_16KHZ_32KBITRATE_MONO_MP3: { tag: "audio-16khz-32kbitrate-mono-mp3", ext: ".mp3", mimeType: "audio/mpeg" },
    AUDIO_24KHZ_96KBITRATE_MONO_MP3: { tag: "audio-24khz-96kbitrate-mono-mp3", ext: ".mp3", mimeType: "audio/mpeg" },
    RIFF_8KHZ_8BIT_MONO_PCM: { tag: "riff-8khz-8bit-mono-mulaw", ext: ".wav", mimeType: "audio/wav" },
    RIFF_16KHZ_16BIT_MONO_PCM: { tag: "riff-16khz-16bit-mono-pcm", ext: ".wav", mimeType: "audio/wav" }
  }
};

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function buildWebSocketURL() {
  const url = new URL("wss://speech.platform.bing.com/consumer/speech/synthesize/readaloud/edge/v1");
  url.searchParams.set("TrustedClientToken", "6A5AA1D4EAFF4E9FB37E23D68491D6F4");
  return url.toString();
}

class TTS {
  static defaults = {
    voice: "en-US-GuyNeural",
    pitch: "+0Hz",
    rate: "+0%",
    volume: "+0%",
    text: null,
    fileType: constants.OUTPUT_FORMATS.AUDIO_24KHZ_48KBITRATE_MONO_MP3,
  };

  constructor({
    voice = TTS.defaults.voice,
    pitch = TTS.defaults.pitch,
    rate = TTS.defaults.rate,
    volume = TTS.defaults.volume,
    text,
    fileType = TTS.defaults.fileType,
  } = TTS.defaults) {
    this.voice = voice;
    this.pitch = pitch;
    this.rate = rate;
    this.volume = volume;
    this.text = text;
    this.fileType = fileType;
  }

  generateSSML() {
    let ssml = "";
    ssml += "X-RequestId:";
    ssml += uuid();
    ssml += "\r\nContent-Type:application/ssml+xml";
    ssml += `\r\nX-Timestamp:${new Date()}Z`;
    ssml += "\r\nPath:ssml";
    ssml += "\r\n\r\n<speak version='1.0' xmlns='http://www.w3.org/2001/10/synthesis' xml:lang='en-US'>";
    ssml += `\r\n\t<voice name='${this.voice}'>`;
    ssml += `\r\n\t\t<prosody pitch='${this.pitch}' rate='${this.rate}' volume='${this.volume}'>`;
    ssml += `\r\n\t\t\t${this.text}`;
    ssml += "\r\n\t\t</prosody>";
    ssml += "\r\n\t</voice>";
    ssml += "\r\n</speak>";
    return ssml;
  }

  generateCommand() {
    let command = "";
    command += `X-Timestamp:${new Date()}`;
    command += "\r\nContent-Type:application/json; charset=utf-8";
    command += "\r\nPath:speech.config";
    command += `\r\n\r\n{"context":{"synthesis":{"audio":{"metadataoptions":{"sentenceBoundaryEnabled":false,"wordBoundaryEnabled":true},"outputFormat":"${this.fileType.tag}"}}}}\r\n`;
    return command;
  }

  setVoiceParams({
    voice = this.voice,
    pitch = this.pitch,
    rate = this.rate,
    volume = this.volume,
    text = this.text,
    fileType = this.fileType,
  }) {
    this.voice = voice;
    this.pitch = pitch;
    this.rate = rate;
    this.volume = volume;
    this.text = text;
    this.fileType = fileType;
  }
}

class EdgeTTSBrowser {
  static fileTypes = constants.OUTPUT_FORMATS;

  static async getVoices() {
    try {
      const response = await fetch(constants.VOICE_LIST_URL, {
        headers: constants.VOICE_HEADERS,
      });
      const data = await response.json();
      return data;
    } catch (e) {
      console.error(e);
      return e;
    }
  }

  constructor(tts) {
    this.url = buildWebSocketURL();
    this.tts = new TTS(tts);
    this.file = new Uint8Array();
  }

  ttsToFile(fileName = "") {
    return new Promise((resolve, reject) => {
      if (!this.tts.text) {
        return reject("there is no text input");
      }

      const socket = new WebSocket(this.url);
      socket.binaryType = "arraybuffer";

      socket.addEventListener("error", (e) => {
        socket.close();
        reject(e.toString());
      });

      socket.addEventListener("close", (e) => {
        if (this.file.length === 0) {
          return reject(new Error("the file buffer is empty"));
        }

        try {
          const blob = new Blob([this.file], {
            type: this.tts.fileType.mimeType || "audio/wav",
          });
          resolve(blob);
        } catch (err) {
          console.error("Error creating file:", err);
          reject(err.toString());
        }
      });

      socket.addEventListener("open", () => {
        socket.send(this.tts.generateCommand());
        socket.send(this.tts.generateSSML());
      });

      socket.addEventListener("message", (data) => {
        if (data.data instanceof ArrayBuffer) {
          const buffer = new Uint8Array(data.data);
          if (buffer.length >= 2) {
            const headerLength = (buffer[0] << 8) | (buffer[1] + "\r\n".length);
            const header = buffer.subarray(0, headerLength);
            const result = this.#parseMessageText(new TextDecoder().decode(header));

            if (result.Path !== "audio") {
              return;
            }

            const payload = buffer.subarray(headerLength);
            const newFile = new Uint8Array(this.file.length + payload.length);
            newFile.set(this.file);
            newFile.set(payload, this.file.length);
            this.file = newFile;
          } else {
            console.error("Received data is too short to contain a valid header.");
          }
        } else if (typeof data.data === "string") {
          const result = this.#parseMessageText(data.data);
          if (result.Path === "turn.end") {
            socket.close();
          }
        }
      });
    });
  }

  #parseMessageText(text) {
    const obj = {};
    const split = text.split("\r\n");

    split
      .filter((line) => line !== "")
      .map((line) => {
        try {
          obj.metaData = JSON.parse(line);
        } catch {
          const [key, value] = line.split(":");
          obj[key] = value;
        }
      });

    return obj;
  }
}

window.EdgeTTSBrowser = EdgeTTSBrowser;